import UIKit

func quickSort(inout a:[Int],l:Int,r:Int){

    if l < r {
        var i = l, j = r ,x = a[i]
        while i < j && a[j] >= x{
            j -= 1
        }
        if i < j {
            a[i] = a[j]
            i += 1
        }
        while i < j && a[i] < x {
            i += 1
        }
        if i < j {
            a[j] = a[i]
            j -= 1
        }
        a[i] = x
        quickSort(&a, l: l, r: i-1)
        quickSort(&a, l: i+1, r: r)
    }   
}
var b = [8,7,6,5,4,3,2,1]
quickSort(&b, l: 0, r: 7)   
print(b)

```

- c版本

```
#include <stdio.h>

///三个参数 a要排序的 数组， l扫左边的  r扫右边
void quickSort(int a[],int l, int r){
    /// 左边要小于 右边才有意义
    if (l < r){
        //保存 一下  ，基准定为X
        int i = l, j = r, x = a[i];
        ///左边小于右边才开始循环，排序里面
        while (i < j) {
            ///从 右边开始向左查找，小于 基准X的值。
            while (i < j && a[j] >= x)
                j--;
            if (i < j)
                a[i++] = a[j];///调换 他们的值
            ///该从左边开始向右查找 比基准x大与等于值
            while (i < j && a[i] < x)
                i++;
            if (i < j)
                a[j--] = a[i];
        }
        ///然后把 x的值 赋值回去
        a[i] = x;

        ///递归 左边
        quickSort(a, l, i-1);
        ///右边
        quickSort(a, i+1, r);   
    }
}

int main() {
    int a[8] = {8,7,6,5,4,3,2,1};
    quickSort(a, 0, 7);
    for (int i = 0; i < 8; i++) {
        printf("%d",a[i]);
    }
    printf("\n");
    return 0;
}
